// Filtra APENAS mensagens de GRUPO com IMAGEM ou PDF ou COMANDOS
const body = $input.item.json.body || $input.item.json;
const data = body.data || body;

const isGroup = (data.key?.remoteJid || '').endsWith('@g.us');

const hasImage = !!(data.message?.imageMessage || data.message?.documentWithCaptionMessage?.message?.imageMessage || data.message?.viewOnceMessage?.message?.imageMessage || data.message?.viewOnceMessageV2?.message?.imageMessage);

const strMessage = JSON.stringify(data.message || {});
const hasPDF = strMessage.includes('application/pdf');

// Verifica se é comando de texto
const textMsg = data.message?.extendedTextMessage?.text || data.message?.conversation || '';
const isCommand = textMsg.trim().startsWith('/');

if (!isGroup || (!hasImage && !hasPDF && !isCommand)) {
  return [{ json: { skip: true } }];
}

const remoteJid = data.key?.remoteJid || '';
const grupoId = remoteJid;
const grupoNome = data.pushName || data.verifiedBizName || remoteJid;
const remetenteId = data.key?.participant || data.participant || '';
const msgTimestamp = new Date((data.messageTimestamp || Date.now() / 1000) * 1000).toISOString();

let mimeType = 'image/jpeg';
let captionText = textMsg; // Para comandos, passamos o próprio texto como caption

if (data.message?.imageMessage) {
  captionText = data.message.imageMessage.caption || '';
  mimeType = data.message.imageMessage.mimetype || 'image/jpeg';
} else if (hasPDF) {
  captionText = strMessage.match(/"caption":"([^"]*)"/)?.[1] || '';
  mimeType = 'application/pdf';
}

// rawFullData = objeto COMPLETO que a Evolution precisa receber
return [{
  json: {
    skip: false,
    isCommand,
    grupoId,
    grupoNome,
    remetenteId,
    msgTimestamp,
    mimeType,
    captionText,
    remoteJid,
    rawFullData: data,
    messageId: data.key?.id || ''
  }
}];

// Prepara payload para IA
const base64 = $('Baixar Mídia (Base64)').item.json.base64 || '';
const mimeType = $('Filtrar Grupos + Imagem').item.json.mimeType || 'image/jpeg';
const caption = $('Filtrar Grupos + Imagem').item.json.captionText || '';

if (!base64) {
  return [{ json: { error: 'Base64 vazio', ...$('Filtrar Grupos + Imagem').item.json } }];
}

// 1. Pega o prompt base que você configurou no "Edit Fields" (Dados da IA)
let promptBase = $('Dados da IA').item.json.prompt1;

// 2. Concatena a mensagem que o cliente enviou no WhatsApp
const prompt = promptBase + `\n\nTexto adicional da mensagem do cliente: ${caption}`;

return [{
  json: {
    base64,
    mimeType,
    prompt,
    context: $('Filtrar Grupos + Imagem').item.json
  }
}];

