// Parse resposta Gemini OU OpenRouter (Backup)
let raw = '';
try {
  // Tenta puxar o formato do Google Gemini primeiro
  raw = $input.item.json.candidates?.[0]?.content?.parts?.[0]?.text;

  // Se veio vazio, significa que é do OpenRouter, então puxa o formato dele
  if (!raw) {
    raw = $input.item.json.choices?.[0]?.message?.content;
  }
} catch(e) { raw = ''; }

raw = (raw || '').trim();
if (raw.startsWith('```')) {
  raw = raw.replace(/^```[a-z]*\n?/,'').replace(/```$/,'').trim();
}

const context = $('Preparar Prompt IA').item.json.context;

if (!raw || raw === 'null') {
  return [{ json: { identificado: false, context, rawResponse: raw } }];
}

let parsed;
try { parsed = JSON.parse(raw); } catch(e) {
  return [{ json: { identificado: false, context, rawResponse: raw, parseError: e.message } }];
}

if (!parsed || !parsed.tipo) {
  return [{ json: { identificado: false, context, rawResponse: raw } }];
}

// Validações mínimas — CARTAO
if (parsed.tipo === 'CARTAO') {
  if (!parsed.valor || !parsed.parcelas) {
    return [{ json: { identificado: false, context, rawResponse: raw, motivo: 'CARTAO sem valor ou parcelas' } }];
  }
  // Bandeira é OBRIGATÓRIA — sem ela o comprovante é inválido
  const bandeira = (parsed.bandeira || '').toString().trim();
  const bandeiraInvalida = !bandeira || bandeira.toLowerCase() === 'null' || bandeira.toLowerCase() === 'desconhecida' || bandeira.toLowerCase() === 'outro';
  if (bandeiraInvalida) {
    return [{ json: { identificado: false, context, rawResponse: raw, motivo: 'CARTAO sem bandeira identificada' } }];
  }
}

// Validações mínimas — PIX
if (parsed.tipo === 'PIX') {
  if (!parsed.valor || !parsed.bancoOrigem || !parsed.bancoDestino) {
    return [{ json: { identificado: false, context, rawResponse: raw, motivo: 'PIX sem valor/origem/destino' } }];
  }
}

return [{ json: { identificado: true, dados: parsed, context } }];

// Verifica se o Apps Script confirmou gravação
const resp = $input.item.json;
const dadosAI = $('Parsear Resposta IA').item.json;

if (!resp.sucesso) {
  return [{ json: { gravado: false, erro: resp.erro || 'Falha no script', dadosAI, dadosScript: resp.dados } }];
}

const d = resp.dados;
const fmt = (v) => {
  const n = parseFloat(v);
  return isNaN(n) ? 'N/D' : 'R$ ' + n.toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g, '.');
};

const pct = d.taxa !== undefined ? d.taxa : 0;
const valorTaxaStr = fmt(d.valorTaxa || 0);

const strPix = fmt(d.saldoPix || 0);
const strCartao = fmt(d.saldoCartao || 0);
const strTotal = fmt(d.saldoTotal || 0);
const strAnterior = fmt((d.saldoTotal || 0) - (d.valorLiq || 0));

let mensagem = '';

if (d.tipo === 'CARTAO') {
  const parcelaLabel = (dadosAI.dados?.parcelas || 'N/D');
  mensagem = `💳 *Comprovante Cartão Registrado*✅\n\n`
    + `💰 *Valor Líquido: ${fmt(d.valorLiq)}*\n\n`
    + `Parcela: Cartão ${parcelaLabel} | Bruto: ${fmt(d.valorBruto)} | Taxa: ${pct}% (${valorTaxaStr})\n`
    + `Banco: ${d.banco || 'N/D'} | ${d.empresaMaquininha || 'N/D'}\n`
    + `Bandeira: ${d.bandeira || 'N/D'}\n`
    + `Data: ${dadosAI.dados?.data || 'N/D'} ${dadosAI.dados?.hora || ''}\n`
    + `Autenticação: ${d.autenticacao || dadosAI.dados?.codigoAutenticacao || dadosAI.dados?.autenticacao || 'N/D'}\n\n`
    + `📊 *Saldo atual Cartão: ${strCartao}*\n`
    + `📊 *Saldo atual Pix: ${strPix}*\n\n`
    + `💱 *Saldo anterior total: ${strAnterior}*\n`
    + `💵 *Saldo atual total: ${strTotal}*\n\n`
    + `🆔 Lançamento: ${d.id || 'N/D'}\n`
    + `🆔 Grupo: ${dadosAI.context?.grupoNome || ''}`;
} else {
  mensagem = `🪙 *Comprovante Pix Registrado* ✅\n\n`
    + `💰 *Valor Líquido: ${fmt(d.valorLiq)}*\n\n`
    + `Parcela: PIX | Bruto: ${fmt(d.valorBruto)} | Taxa: ${pct}% (${valorTaxaStr})\n`
    + `Banco de Origem: ${d.bancoOrigem || 'N/D'} | Pagador: ${d.nomePagador || 'N/D'}\n`
    + `Banco de Destino: ${d.bancoDestino || 'N/D'} | Recebedor: ${d.nomeRecebedor || 'N/D'}\n`
    + `Data: ${dadosAI.dados?.data || 'N/D'} ${dadosAI.dados?.hora || ''}\n`
    + `Autenticação: ${d.codigoAutenticacao || dadosAI.dados?.codigoAutenticacao || dadosAI.dados?.autenticacao || 'N/D'}\n\n`
    + `📊 *Saldo atual Cartão: ${strCartao}*\n`
    + `📊 *Saldo atual Pix: ${strPix}*\n\n`
    + `💱 *Saldo anterior total: ${strAnterior}*\n`
    + `💵 *Saldo atual total: ${strTotal}*\n\n`
    + `🆔 Lançamento: ${d.id || 'N/D'}\n`
    + `🆔 Grupo: ${dadosAI.context?.grupoNome || ''}`;
}

return [{ json: {
  gravado: true,
  mensagem,
  remoteJid: dadosAI.context?.remoteJid,
  grupoId: dadosAI.context?.grupoId
} }];

