const json = $input.item.json;

// 1. Pegar as variáveis que já vieram mastigadas do nó de Filtro!
const texto = json.captionText || '';
const remetenteId = json.remetenteId || '';
// Às vezes o participant oficial vem no participantAlt
const altRemetenteId = json.rawFullData?.key?.participantAlt || '';

const grupoId = json.grupoId || '';
const grupoNome = json.grupoNome || '';

// 2. Verificar se é um comando
if (!texto.startsWith('/')) {
  return []; // Se não for comando, ignora este caminho
}

// 3. WHITELIST - Coloque os números dos Administradores autorizados aqui!
// Formato: 55DDDNUMERO@s.whatsapp.net
const admins = [
  "5511999999999@s.whatsapp.net", 
  "553391357195@s.whatsapp.net"
];

if (!admins.includes(remetenteId) && !admins.includes(altRemetenteId)) {
  return []; // Se não for admin, morre aqui silenciosamente (não retorna erro)
}

// 4. Quebrar o comando (Ex: /cancelar X7K2A Valor errado)
const partes = texto.trim().split(' ');
const comando = partes[0].substring(1).toLowerCase(); // tirar a barra

let payload = {
  action: "comando_admin",
  comando: comando,
  remetenteId: remetenteId,
  grupoId: grupoId,
  grupoNome: grupoNome,
  idAlvo: "",
  valor: 0,
  motivo: ""
};

if (comando === "cancelar") {
  payload.idAlvo = partes[1] || "";
  payload.motivo = partes.slice(2).join(' ');
} else if (comando === "entrada" || comando === "retirada") {
  payload.valor = partes[1] || "0";
  payload.motivo = partes.slice(2).join(' ');
} else {
  return [{ json: { erro: "Comando inválido. Use /cancelar, /entrada ou /retirada.", grupoId, remetenteId } }];
}

return [{ json: payload }];

const relatorio = $('Separar por Grupo').item.json;

const fmt = (v) => 'R$ ' + parseFloat(v).toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g, '.');

const msg = `*Fechamento do dia ${relatorio.hoje}*\n\nRecebido: ${fmt(relatorio.recebido)}\nPago: ${fmt(relatorio.pago)}\nTaxas: ${fmt(relatorio.taxas)}\nTransações: ${relatorio.transacoes}\n\n*Saldo final: ${fmt(relatorio.saldoFinal)}*\n\nValidar!`;

return [{ json: {
  grupoId: relatorio.grupoId,
  mensagem: msg
}}];
